import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import ContactForm from '../components/ContactForm.astro';
import PrayerRequestForm from '../components/PrayerRequestForm.astro';
import RideRequestForm from '../components/RideRequestForm.astro';
import ConnectForm from '../components/ConnectForm.astro';

const title = 'Contact | First Ithaca Chinese Christian Church';
const description =
  'Get in touch with First Ithaca Chinese Christian Church. Send a message, submit a prayer request, request a ride, or connect with us.';

const siteKey = import.meta.env.PUBLIC_TURNSTILE_SITE_KEY ?? '';
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title="Contact Us"
      subtitle="We'd love to hear from you"
      backgroundImage="/images/hero-placeholder.svg"
    />

    <section class="contact-section" aria-label="Contact">
      <div class="contact-section__inner">
        <div class="contact-layout">
          <!-- Tabbed forms -->
          <div class="contact-tabs">
            <div class="contact-tabs__list" role="tablist" aria-label="Contact form options">
              <button
                class="contact-tabs__tab contact-tabs__tab--active"
                role="tab"
                aria-selected="true"
                aria-controls="panel-contact"
                id="tab-contact"
                tabindex="0"
              >
                General Contact
              </button>
              <button
                class="contact-tabs__tab"
                role="tab"
                aria-selected="false"
                aria-controls="panel-prayer"
                id="tab-prayer"
                tabindex="-1"
              >
                Prayer Request
              </button>
              <button
                class="contact-tabs__tab"
                role="tab"
                aria-selected="false"
                aria-controls="panel-ride"
                id="tab-ride"
                tabindex="-1"
              >
                Ride Request
              </button>
              <button
                class="contact-tabs__tab"
                role="tab"
                aria-selected="false"
                aria-controls="panel-connect"
                id="tab-connect"
                tabindex="-1"
              >
                Connect With Us
              </button>
            </div>

            <div
              class="contact-tabs__panel contact-tabs__panel--active"
              role="tabpanel"
              id="panel-contact"
              aria-labelledby="tab-contact"
              tabindex="0"
            >
              <ContactForm />
            </div>

            <div
              class="contact-tabs__panel"
              role="tabpanel"
              id="panel-prayer"
              aria-labelledby="tab-prayer"
              tabindex="0"
              hidden
            >
              <PrayerRequestForm />
            </div>

            <div
              class="contact-tabs__panel"
              role="tabpanel"
              id="panel-ride"
              aria-labelledby="tab-ride"
              tabindex="0"
              hidden
            >
              <RideRequestForm />
            </div>

            <div
              class="contact-tabs__panel"
              role="tabpanel"
              id="panel-connect"
              aria-labelledby="tab-connect"
              tabindex="0"
              hidden
            >
              <ConnectForm />
            </div>
          </div>

          <!-- Church info sidebar -->
          <aside class="contact-info" aria-label="Church contact information">
            <h2 class="contact-info__heading">Church Information</h2>

            <div class="contact-info__block">
              <h3 class="contact-info__label">Address</h3>
              <address class="contact-info__value">
                First Ithaca Chinese Christian Church<br />
                309 College Ave<br />
                Ithaca, NY 14850
              </address>
            </div>

            <div class="contact-info__block">
              <h3 class="contact-info__label">Sunday Service</h3>
              <p class="contact-info__value">
                English Worship: 11:00 AM<br />
                Chinese Worship: 11:00 AM
              </p>
            </div>

            <div class="contact-info__block">
              <h3 class="contact-info__label">Email</h3>
              <p class="contact-info__value">
                <a href="mailto:info@ficcc.org" class="contact-info__link">info@ficcc.org</a>
              </p>
            </div>

            <div class="contact-info__block">
              <h3 class="contact-info__label">Phone</h3>
              <p class="contact-info__value">
                <a href="tel:+16072731223" class="contact-info__link">(607) 273-1223</a>
              </p>
            </div>
          </aside>
        </div>
      </div>
    </section>
  </main>
</BaseLayout>

<!-- Turnstile loaded in explicit mode — only one widget renders at a time -->
<script is:inline src="https://challenges.cloudflare.com/turnstile/v0/api.js?render=explicit" async defer></script>

<script is:inline>
(function () {
  var tablist = document.querySelector('.contact-tabs__list');
  if (!tablist) return;

  var tabs = Array.prototype.slice.call(tablist.querySelectorAll('[role="tab"]'));
  var panels = tabs.map(function (tab) {
    return document.getElementById(tab.getAttribute('aria-controls'));
  });

  /* Turnstile site key — read from first cf-turnstile div in active panel */
  var siteKey = '';
  var firstWidget = document.querySelector('.cf-turnstile[data-sitekey]');
  if (firstWidget) {
    siteKey = firstWidget.getAttribute('data-sitekey') || '';
  }

  /* Track current Turnstile widget ID so we can remove it on switch */
  var currentWidgetId = null;

  function renderTurnstile(panel) {
    /* Remove previous widget if any */
    if (currentWidgetId !== null && typeof turnstile !== 'undefined') {
      try { turnstile.remove(currentWidgetId); } catch (_) {}
      currentWidgetId = null;
    }

    if (typeof turnstile === 'undefined' || !siteKey) return;

    var container = panel.querySelector('.cf-turnstile');
    if (!container) return;

    /* Clear any stale children from previous renders */
    container.innerHTML = '';

    currentWidgetId = turnstile.render(container, {
      sitekey: siteKey,
      theme: 'light',
    });
  }

  function switchTab(newTab) {
    var newIndex = tabs.indexOf(newTab);
    if (newIndex === -1) return;

    /* Deactivate all */
    tabs.forEach(function (tab, i) {
      tab.classList.remove('contact-tabs__tab--active');
      tab.setAttribute('aria-selected', 'false');
      tab.setAttribute('tabindex', '-1');
      panels[i].hidden = true;
      panels[i].classList.remove('contact-tabs__panel--active');
    });

    /* Activate new */
    newTab.classList.add('contact-tabs__tab--active');
    newTab.setAttribute('aria-selected', 'true');
    newTab.setAttribute('tabindex', '0');
    newTab.focus();
    panels[newIndex].hidden = false;
    panels[newIndex].classList.add('contact-tabs__panel--active');

    /* Render Turnstile for newly visible panel */
    renderTurnstile(panels[newIndex]);
  }

  /* Click handler */
  tabs.forEach(function (tab) {
    tab.addEventListener('click', function () {
      switchTab(tab);
    });
  });

  /* Keyboard navigation — arrow keys between tabs, Home/End */
  tablist.addEventListener('keydown', function (e) {
    var currentIndex = tabs.indexOf(document.activeElement);
    if (currentIndex === -1) return;

    var newIndex;

    switch (e.key) {
      case 'ArrowRight':
      case 'ArrowDown':
        newIndex = (currentIndex + 1) % tabs.length;
        break;
      case 'ArrowLeft':
      case 'ArrowUp':
        newIndex = (currentIndex - 1 + tabs.length) % tabs.length;
        break;
      case 'Home':
        newIndex = 0;
        break;
      case 'End':
        newIndex = tabs.length - 1;
        break;
      default:
        return;
    }

    e.preventDefault();
    switchTab(tabs[newIndex]);
  });

  /* Initial Turnstile render for the default active panel */
  function initTurnstile() {
    if (typeof turnstile !== 'undefined') {
      var activePanel = document.querySelector('.contact-tabs__panel--active');
      if (activePanel) renderTurnstile(activePanel);
    }
  }

  /* Turnstile script may load after this script — poll briefly */
  if (typeof turnstile !== 'undefined') {
    initTurnstile();
  } else {
    var attempts = 0;
    var interval = setInterval(function () {
      attempts++;
      if (typeof turnstile !== 'undefined') {
        clearInterval(interval);
        initTurnstile();
      } else if (attempts > 50) {
        clearInterval(interval); /* give up after ~5s */
      }
    }, 100);
  }
})();
</script>

<style>
  .contact-section {
    padding: var(--space-20) var(--space-6);
    background-color: var(--color-bg);
  }

  .contact-section__inner {
    max-width: var(--max-width, 72rem);
    margin: 0 auto;
  }

  /* Layout: forms + sidebar */
  .contact-layout {
    display: grid;
    grid-template-columns: 1fr 20rem;
    gap: var(--space-16);
    align-items: start;
  }

  /* ---------- Tabs ---------- */

  .contact-tabs__list {
    display: flex;
    gap: var(--space-1);
    border-bottom: 2px solid var(--color-stone);
    margin-bottom: var(--space-8);
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
  }

  .contact-tabs__tab {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 600;
    color: var(--color-body);
    background: none;
    border: none;
    border-bottom: 2px solid transparent;
    margin-bottom: -2px;
    padding: var(--space-3) var(--space-4);
    cursor: pointer;
    white-space: nowrap;
    transition: color var(--transition), border-color var(--transition);
  }

  .contact-tabs__tab:hover {
    color: var(--color-ink);
  }

  .contact-tabs__tab--active {
    color: var(--color-terracotta);
    border-bottom-color: var(--color-terracotta);
  }

  .contact-tabs__tab:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: -2px;
    border-radius: var(--radius-sm) var(--radius-sm) 0 0;
  }

  .contact-tabs__panel {
    animation: contact-fadeIn 0.2s ease;
  }

  .contact-tabs__panel[hidden] {
    display: none;
  }

  @keyframes contact-fadeIn {
    from { opacity: 0; transform: translateY(4px); }
    to { opacity: 1; transform: translateY(0); }
  }

  /* ---------- Church info sidebar ---------- */

  .contact-info {
    background-color: var(--color-cream);
    border-radius: var(--radius-md, 0.5rem);
    padding: var(--space-8);
  }

  .contact-info__heading {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    font-weight: 700;
    color: var(--color-ink);
    margin: 0 0 var(--space-6) 0;
  }

  .contact-info__block {
    margin-bottom: var(--space-6);
  }

  .contact-info__block:last-child {
    margin-bottom: 0;
  }

  .contact-info__label {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 600;
    color: var(--color-ink);
    margin: 0 0 var(--space-1) 0;
  }

  .contact-info__value {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-body);
    line-height: 1.6;
    margin: 0;
    font-style: normal;
  }

  .contact-info__link {
    color: var(--color-terracotta);
    text-decoration: none;
    transition: color var(--transition);
  }

  .contact-info__link:hover {
    text-decoration: underline;
  }

  .contact-info__link:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
    border-radius: 2px;
  }

  /* ---------- Responsive ---------- */

  @media (max-width: 768px) {
    .contact-layout {
      grid-template-columns: 1fr;
      gap: var(--space-10);
    }

    .contact-tabs__list {
      gap: 0;
    }

    .contact-tabs__tab {
      font-size: var(--text-xs, 0.75rem);
      padding: var(--space-2) var(--space-3);
    }
  }
</style>

